                        err.push(' ');
                    }
                    for _ in 0..caret_count {
                        err.push('^');
                    }
                    return Some(err);
                }
                i = j;
                continue;
            }
            // $ followed by letter/_/digit/anything else - not ambiguous (handled by regex)
            i += 1;
        } else {
            i += 1;
        }
    }
    None
}

