use std::fs;
use std::io::Write;
use std::path::Path;

use crate::replacer::Replacer;

/// Try to replace contents of file in-place via a temp file in the same dir.
/// On failure, return a string representation of the error in sd's format:
///   "<path>: <io error> at path \"<temp path>\""
pub fn replace_in_place(path: &Path, replacer: &Replacer) -> Result<(), String> {
    // Read contents
    let content = match fs::read(path) {
        Ok(c) => c,
        Err(e) => {
            // sd's format includes "at path" of the temp file, but we may not have created one yet
            return Err(format!("{}: {}", path.display(), io_err_format(&e)));
        }
    };

    // Resolve target: follow symlinks so we modify the target file's data
    // but place the temp file next to the link target.
    let target = match fs::canonicalize(path) {
        Ok(p) => p,
        Err(_) => path.to_path_buf(),
    };

    // Parent dir for the temp file
    let parent = target.parent().unwrap_or(Path::new("."));

    // Build temp file path
    let temp_path = parent.join(format!(".tmp{}", random_suffix(6)));

    // Compute replaced contents
    let out = replacer.replace(&content);

    // Get target file's permissions for preservation
    let metadata = fs::metadata(&target).ok();

    // Write to temp file
    let res = (|| -> std::io::Result<()> {
        let mut f = fs::OpenOptions::new()
            .write(true)
            .create_new(true)
            .open(&temp_path)?;
        f.write_all(&out)?;
        f.sync_all()?;
        drop(f);

        // Set permissions on temp file to match target
        if let Some(m) = &metadata {
            let perm = m.permissions();
            let _ = fs::set_permissions(&temp_path, perm);
        }

        // Atomically rename to target
        fs::rename(&temp_path, &target)?;
        Ok(())
    })();

    if let Err(e) = res {
        // Clean up temp file if it exists
        let _ = fs::remove_file(&temp_path);
        return Err(format!(
            "{}: {} at path \"{}\"",
            path.display(),
            io_err_format(&e),
            temp_path.display()
        ));
    }

    Ok(())
}

fn io_err_format(e: &std::io::Error) -> String {
    // Match format like "Permission denied (os error 13)"
    if let Some(code) = e.raw_os_error() {
        format!("{} (os error {})", strerror(code), code)
    } else {
        format!("{}", e)
    }
}

fn strerror(code: i32) -> &'static str {
    match code {
        1 => "Operation not permitted",
        2 => "No such file or directory",
        5 => "Input/output error",
        9 => "Bad file descriptor",
        13 => "Permission denied",
        17 => "File exists",
        19 => "No such device",
        21 => "Is a directory",
        28 => "No space left on device",
        30 => "Read-only file system",
        32 => "Broken pipe",
        _ => "Unknown error",
    }
}

fn random_suffix(n: usize) -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let mut seed = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos() as u64)
        .unwrap_or(0);
    seed ^= std::process::id() as u64;
    seed = seed.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
    let mut s = String::with_capacity(n);
    let alphabet: &[u8] = b"abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    for _ in 0..n {
        seed = seed.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
        let idx = ((seed >> 32) as usize) % alphabet.len();
        s.push(alphabet[idx] as char);
    }
    s
}

