    use clap::error::ErrorKind;
    // We can't easily override the help title via clap derive. Use command_for_update.
    let mut cmd = <Args as clap::CommandFactory>::command();
    // Set custom long_about (the help title is part of the help template).
    cmd = cmd
        .name("executable")
        .version("1.0.0")
        // Override default version flag handler so we print "sd 1.0.0" not "executable 1.0.0".
        .long_version("1.0.0");

    // Customize the help template to begin with `sd v1.0.0` line.
    cmd = cmd.help_template(
        "sd v1.0.0\n\
         {about}\n\n\
         {usage-heading} {usage}\n\n\
         {all-args}{after-help}",
    );

    // For version output, we want exactly: "sd 1.0.0\n"
    // clap by default prints `{name} {version}\n`. Override via mut_arg on version?
    // We'll handle by intercepting the ErrorKind::DisplayVersion path.
    let m = cmd.try_get_matches();
    match m {
        Ok(matches) => {
            let args = <Args as clap::FromArgMatches>::from_arg_matches(&matches)
                .expect("clap derive should succeed if matches succeeded");
            Ok(args)
        }
        Err(e) => {
            match e.kind() {
                ErrorKind::DisplayVersion => {
                    // Print "sd 1.0.0\n" instead of "executable 1.0.0\n"
                    print!("sd 1.0.0\n");
                    Err(0)
                }
                ErrorKind::DisplayHelp => {
                    // clap prints the help via its template; just exit 0.
                    let _ = e.print();
                    Err(0)
                }
                _ => {
                    let _ = e.print();
                    Err(2)
                }
            }
        }
    }
}

fn run(args: Args) -> Result<(), u8> {
    // Build the regex from FIND + flags
    let replacer = match Replacer::new(
        args.find,
        args.replace_with,
        args.fixed_strings,
        args.flags.as_deref(),
        args.max_replacements,
    ) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("{}", e);
            return Err(1);
        }
    };

    if args.files.is_empty() {
        // stdin -> stdout
        let mut buf = Vec::new();
        if io::stdin().read_to_end(&mut buf).is_err() {
            eprintln!("error: failed to read stdin");
            return Err(1);
        }
        let out = replacer.replace(&buf);
        if io::stdout().write_all(&out).is_err() {
            eprintln!("error: Broken pipe (os error 32)");
            return Err(1);
        }
        return Ok(());
    }

    // Validate all paths first: must exist
    for p in &args.files {
        if !p.exists() {
            eprintln!("error: invalid path: {}", p.display());
            return Err(1);
        }
    }

    // Open all files via mmap up front; if any fail, abort
    let sources = match input::open_sources(&args.files) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error: {}", e);
            return Err(1);
        }
    };

    if args.preview {
        let multi = sources.len() > 1;
        let mut stdout = io::stdout().lock();
        for src in &sources {
            let out = replacer.replace(&src.bytes);
            if multi {
                let _ = writeln!(stdout, "----- FILE {} -----", src.path.display());
            }
            let _ = stdout.write_all(&out);
        }
        return Ok(());
    }

    // In-place modification
    let mut errors: Vec<String> = Vec::new();
    for src in &sources {
        if let Err(e) = input::write_in_place(src, &replacer) {
            errors.push(e);
        }
    }

    if !errors.is_empty() {
        eprintln!("error: Failed processing some inputs");
        for e in errors {
            eprintln!("    {}", e);
        }
        eprintln!();
        return Err(1);
    }

    Ok(())
}

use regex::bytes::{Regex, RegexBuilder};
use std::borrow::Cow;

use crate::replace::{check_ambiguous_groups, decode_replacement_escapes};

pub struct Replacer {
    regex: Regex,
    replace_with: Vec<u8>,
    is_literal: bool,
    max_replacements: usize,
}

impl Replacer {
    pub fn new(
        find: String,
        replace_with: String,
        is_literal: bool,
        flags: Option<&str>,
        max_replacements: usize,
    ) -> Result<Self, String> {
        // Process the find pattern
        let pattern = if is_literal {
            regex::escape(&find)
        } else {
            find
        };

        // Build regex based on flags
        let (mut pattern, builder_settings) = apply_flag_string(pattern, flags);

        let mut builder = RegexBuilder::new(&pattern);
        builder.multi_line(builder_settings.multi_line);
        builder.case_insensitive(builder_settings.case_insensitive);
        builder.dot_matches_new_line(builder_settings.dot_matches_new_line);

        let regex = match builder.build() {
            Ok(r) => r,
            Err(e) => {
                return Err(format!("error: invalid regex {}", e));
            }
        };

        // Process replacement
        let replace_with_bytes = if is_literal {
            replace_with.into_bytes()
        } else {
            // Check for ambiguous group references
            if let Some(err) = check_ambiguous_groups(&replace_with) {
                return Err(err);
            }
            decode_replacement_escapes(&replace_with)
        };

        Ok(Self {
            regex,
            replace_with: replace_with_bytes,
            is_literal,
            max_replacements,
        })
    }

    pub fn replace<'a>(&self, input: &'a [u8]) -> Cow<'a, [u8]> {
        let limit = if self.max_replacements == 0 {
            usize::MAX
        } else {
            self.max_replacements
        };

        if self.is_literal {
            // Literal replacement (no $N expansion)
            let lit = &self.replace_with[..];
            let mut result: Vec<u8> = Vec::new();
            let mut last = 0;
            let mut count = 0;
            for m in self.regex.find_iter(input) {
                if count >= limit {
                    break;
                }
                result.extend_from_slice(&input[last..m.start()]);
                result.extend_from_slice(lit);
                last = m.end();
                count += 1;
            }
            if count == 0 {
                return Cow::Borrowed(input);
            }
            result.extend_from_slice(&input[last..]);
            Cow::Owned(result)
        } else {
            // Use regex's replacement with $ support
            self.regex.replacen(input, limit, &self.replace_with[..])
        }
    }
}

#[derive(Default)]
pub struct BuilderSettings {
    pub multi_line: bool,
    pub case_insensitive: bool,
    pub dot_matches_new_line: bool,
}

pub fn apply_flag_string(pattern: String, flags: Option<&str>) -> (String, BuilderSettings) {
    let mut settings = BuilderSettings {
        multi_line: true,
        case_insensitive: false,
        dot_matches_new_line: false,
    };

    let mut word = false;

    if let Some(flags) = flags {
        let has_e = flags.contains('e');
        let has_w = flags.contains('w');
        let has_s = flags.contains('s');
        let has_m = flags.contains('m');

        if has_e || has_w || (has_s && !has_m) {
            settings.multi_line = false;
        }

        for c in flags.chars() {
            match c {
                'i' => settings.case_insensitive = true,
                'c' => settings.case_insensitive = false,
                's' => settings.dot_matches_new_line = true,
                'w' => {
                    settings.dot_matches_new_line = false;
                    word = true;
                }
                _ => {}
            }
        }
    }

    let final_pattern = if word {
        format!(r"\b{}\b", pattern)
    } else {
        pattern
    };

    (final_pattern, settings)
}
